export const GetConversionBySourceResponseItem = zod.object({
  source: zod.string(),
  leads: zod.number(),
  enrolled: zod.number(),
  rate: zod.number(),
});
export const GetConversionBySourceResponse = zod.array(
  GetConversionBySourceResponseItem,
);

/**
 * @summary Global search across contacts, campaigns, segments
 */
